import { css } from '@linaria/core'
import React from 'react'
import { CHAT_ATTACHMENT_SERVICE_TYPE } from '../helpers/chatAttachmentHelper'
import { isLinkApproved } from '../helpers/domainWhiteList'
import ChatAttachment, { ChatAboutAttachment, ChatEnrichedUrlAttachment } from './ChatAttachment'
import { useChatProviderContext } from '../providers/useChatProviderContext'

const wrapperCss = css`
  max-width: 336px;
  & > * {
    margin-top: 4px;
  }
`

export default function ChatAttachments({ attachments, fromUser, setAttachmentWithData, isSystemUser }) {
  const { domainWhitelist } = useChatProviderContext()
  return attachments?.length ? (
    <div className={wrapperCss}>
      {attachments?.map((a, i) => {
        if (!a.type && !a.serviceType) return null
        if (a.type && a.type === 'image') {
          // Stream enriches all URLs in a message, but we show only approved ones
          // Don't show url previews for messages from helper connect system user
          if (isLinkApproved(a.title_link, domainWhitelist) && !isSystemUser) {
            return (
              // eslint-disable-next-line react/no-array-index-key -- the same link could be sent twice in a message, so index is necessary for a unique key
              <ChatEnrichedUrlAttachment key={`${a.title_link}${i}`} attachment={a} />
            )
          }
          return null
        }
        if (a.serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.ABOUT) {
          return <ChatAboutAttachment key="aboutAttachmentKey" data={a.data} filename={a.filename} />
        }
        if (
          a.serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE ||
          a.serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT
        ) {
          return (
            <ChatAttachment
              key={a.id}
              id={a.id}
              data={a.data}
              serviceType={a.serviceType}
              fromUser={fromUser}
              setAttachmentWithData={setAttachmentWithData}
            />
          )
        }
        return null
      })}
    </div>
  ) : null
}
